---@class LBlockMiniGameAniActor
local LBlockMiniGameAniActor = LxClass("LBlockMiniGameAniActor", nil)

local AniState = LBlockMiniGameConst.AniState

function LBlockMiniGameAniActor:LBlockMiniGameAniActor(obj)
    self._obj = obj
    self._aniName = nil
    self._endTime = nil

    self._stateFunc = {
        [AniState.Idle] = self.PlayIdle,
        [AniState.Attack] = self.PlayAttack,
        [AniState.Dead] = self.PlayDead,
        [AniState.Run] = self.PlayRun,
    }
end

-- 销毁
function LBlockMiniGameAniActor:Destroy()
end

-- update
function LBlockMiniGameAniActor:Update(dt)
    if self._endTime then
        self._endTime = self._endTime - dt
        if self._endTime <= 0 then
            self._aniName = nil
            self:PlayIdle()
        end
    end
end

-- 设置动画
function LBlockMiniGameAniActor:SetAniState(state, endTime)
    self._endTime = endTime
    self._stateFunc[state](self)
end

-- 播放动画
function LBlockMiniGameAniActor:PlayAni(aniName, loop, aniTime, timescale, mixTime)
    if aniName == self._aniName or self._aniName == LSpineAniConst.die then
        return
    end
    self._aniName = aniName
    self._endTime = aniTime

    timescale = timescale or 1
    local dpObj = self._obj:GetDpObject()
    dpObj:SetAnimationTimeScale(timescale)
    dpObj:PlayAnimation(0, aniName, loop, false, mixTime)
end

-- 待机
function LBlockMiniGameAniActor:PlayIdle()
    self._endTime = nil
    self:PlayAni(LSpineAniConst.idle, true)
end

-- 移动
function LBlockMiniGameAniActor:PlayRun()
    if self._obj:IsTower() then
        self:PlayIdle()
    else
        self._endTime = nil
        self:PlayAni(LSpineAniConst.run, true)
    end
end

-- 死亡
function LBlockMiniGameAniActor:PlayDead()
    self:PlayAni(LSpineAniConst.die, false)

    local dpObj = self._obj:GetDpObject()
    dpObj:SetAnimationCompleteFunc(function(...) self:OnPlayFinish(...) end)
end

-- 播放完成回调
function LBlockMiniGameAniActor:OnPlayFinish(aniName)
    if aniName == LSpineAniConst.die then
        self._obj:DestroySelf()
    end
end

-- 暂停
function LBlockMiniGameAniActor:OnPauseGame()
    local dpObj = self._obj:GetDpObject()
    dpObj:SetAnimationTimeScale(0)
end

-- 恢复
function LBlockMiniGameAniActor:OnResumeGame()
    local dpObj = self._obj:GetDpObject()
    dpObj:SetAnimationTimeScale(1)
end

return LBlockMiniGameAniActor
